-- ============================================================
-- INCREMENTAL V4 - HARDWARE INDUSTRIAL / DEEPTECH / VC-GRADE
-- ------------------------------------------------------------
-- Cette migration ajoute :
--   1. Nouvelles colonnes pour matching plus fin :
--      - asset_class (software_pure / software_with_hardware /
--        hardware_industrial / deep_tech_research / etc.)
--      - vc_relevance_score (1-5, sert de boost de tri)
--      - capital_intensity (low / medium / high / very high)
--      - vertical_v4 (label de vertical detaillee)
--      - source_2, what_made_it_work, key_risks_lessons
--   2. Backfill des 129 lignes V3 sur asset_class + vc_relevance_score
--      par regle deterministe basee sur leur secteur.
--   3. Suppression des doublons V3 (Anduril, Helsing, Shield AI, etc.)
--      qui sont mieux documentes dans V4.
--   4. Insertion des 56 lignes V4 hardware/industrial/deeptech.
--   5. Insertion d ajouts personnels : Pasqal (chiffres frais 2026),
--      Atom Computing, PsiQuantum, Sila Nanotechnologies, QuantumScape,
--      Boom Supersonic, Relativity Space, Sierra Space, Carbon Inc.,
--      Apptronik, 1X Technologies, Sanctuary AI, Symbotic.
--
-- ============================================================

-- 1. Ajout colonnes (idempotent)
alter table public.historical_companies add column if not exists asset_class text;
alter table public.historical_companies add column if not exists vc_relevance_score integer;
alter table public.historical_companies add column if not exists capital_intensity text;
alter table public.historical_companies add column if not exists vertical_v4 text;
alter table public.historical_companies add column if not exists source_2 text;
alter table public.historical_companies add column if not exists what_made_it_work text;
alter table public.historical_companies add column if not exists key_risks_lessons text;

-- 2. Backfill asset_class sur V3 par regle deterministe.
-- Software pur : SaaS, AI, Marketplace, Consumer, Fintech (les Adyen,
-- Spotify, Mistral, OpenAI, Anthropic, Cohere, etc.)
update public.historical_companies set asset_class = 'software_pure'
  where asset_class is null
  and (sector ilike 'AI%' or sector ilike 'SaaS%' or sector ilike 'Fintech%'
       or sector ilike 'E-commerce%' or sector ilike 'Marketplace%'
       or sector ilike 'Consumer%' or sector ilike 'Cybersecurity%'
       or sector ilike 'Gaming%' or sector ilike 'Crypto%' or sector = 'Cloud'
       or sector ilike 'Insurtech%' or sector ilike 'Healthtech%'
       or sector ilike 'Foodtech%');
-- Hardware industrial / deeptech : Quantum, IoT, Mobility (hors digital)
update public.historical_companies set asset_class = 'hardware_industrial'
  where asset_class is null
  and (sector ilike 'Mobility%' or sector ilike 'Greentech%' or sector ilike 'IoT%');
update public.historical_companies set asset_class = 'deep_tech_research'
  where asset_class is null and sector = 'Quantum';
-- Fallback : tout le reste en software_pure
update public.historical_companies set asset_class = 'software_pure'
  where asset_class is null;

-- 3. Backfill vc_relevance_score V3 par defaut a 3
update public.historical_companies set vc_relevance_score = 3
  where vc_relevance_score is null;

-- 4. Suppression doublons V3 qui seront mieux documentes en V4
delete from public.historical_companies where name in (
  'Anduril',
  'Helsing',
  'Shield AI',
  'Skydio',
  'Tekever',
  'Quantum Systems',
  'Wayve',
  'Saildrone',
  'Northvolt',
  'Form Energy',
  'IonQ',
  'PsiQuantum');

-- 5. Insertion V4 - 56 lignes hardware/industrial/deeptech
